INSERT INTO COMPATIBILITY_RULES (Rule_ID, Component_A, Component_B, Condition, Rule_Description) VALUES (1, 1, 1, 'CPU.Socket_Type == MOTHERBOARD.Socket_Type', 'CPU socket must match motherboard socket.');
INSERT INTO COMPATIBILITY_RULES (Rule_ID, Component_A, Component_B, Condition, Rule_Description) VALUES (2, 4, 3, 'RAM.RAM_Type == MOTHERBOARD.RAM_Type', 'RAM type must match motherboard RAM type.');
INSERT INTO COMPATIBILITY_RULES (Rule_ID, Component_A, Component_B, Condition, Rule_Description) VALUES (3, 5, 0, 'PSU.Wattage >= TOTAL_POWER_DRAW', 'PSU wattage must be at least the total estimated power draw.');
INSERT INTO COMPATIBILITY_RULES (Rule_ID, Component_A, Component_B, Condition, Rule_Description) VALUES (4, 2, 3, 'GPU.PCIE_Version <= MOTHERBOARD.PCIE_Version', 'GPU PCIe version above motherboard support is treated as suboptimal.');
